import React, { useState, useCallback, useMemo, useRef } from 'react';
import {
  Button,
  Select,
  MoneyInput,
  NumberInput,
  dispatchAppToast,
  LinPageLayout,
  ErpListHeaderFilters,
  useCatalogTableBusy,
  type LinListToolbarActionDef,
} from '@linm-soft/common-components';
import { hasPermissionCode, useOpeningBalancePermissions } from '../../../hooks/useOpeningBalancePermissions';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningInventoryDto, MaterialDto, WarehouseDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { openingBalancePageLabels } from '../../../constants/openingBalancePageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatVnd } from '../../../utils/formatters';
import { FormMode, isEditingMode, isViewMode } from '../../../components/form/FormMode';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-so-du-vat-tu';
const PAGE_ID = 'kt-so-du-vat-tu';
const labels = openingBalancePageLabels.soDuVatTu;

const cloneItems = (rows: OpeningInventoryDto[]): OpeningInventoryDto[] =>
  rows.map(row => ({ ...row }));

const SoDuVatTuPage: React.FC = () => {
  void hasPermissionCode;
  const { canWrite } = useOpeningBalancePermissions();
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningInventoryDto[]>([]);
  const [materials, setMaterials] = useState<MaterialDto[]>([]);
  const [warehouses, setWarehouses] = useState<WarehouseDto[]>([]);
  const [warehouseFilter, setWarehouseFilter] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formMode, setFormMode] = useState(FormMode.View);
  const snapshotRef = useRef<OpeningInventoryDto[]>([]);

  const isEditing = isEditingMode(formMode);
  const isView = isViewMode(formMode);
  const hasRows = items.length > 0;

  const load = useCallback(() => {
    setLoading(true);
    Promise.all([
      ktService.getOpeningInventory(Number(year)),
      ktService.searchMaterials({ page: 1, pageSize: 500 }),
      ktService.getWarehouses({ page: 1, pageSize: 500, isActive: true }),
    ])
      .then(([inventory, materialRes, warehouseRes]) => {
        setItems(inventory);
        setMaterials(materialRes.items);
        setWarehouses(warehouseRes.items);
        setFormMode(FormMode.View);
      })
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateItem = (idx: number, patch: Partial<OpeningInventoryDto>) => {
    setItems(prev => prev.map((it, i) => {
      if (i !== idx) return it;
      const quantity = patch.quantity ?? it.quantity;
      const unitPrice = patch.unitPrice ?? it.unitPrice;
      return { ...it, ...patch, quantity, unitPrice, amount: quantity * unitPrice };
    }));
  };

  const deleteRow = (idx: number) => {
    setItems(prev => prev.filter((_, i) => i !== idx));
  };

  const addRow = useCallback(() => {
    const defaultWarehouse = warehouses[0];
    setItems(prev => ([
      ...prev,
      {
        materialCode: '',
        materialName: '',
        warehouseId: defaultWarehouse?.id ?? '',
        warehouseName: defaultWarehouse?.name ?? '',
        unitCode: '',
        quantity: 0,
        unitPrice: 0,
        amount: 0,
      },
    ]));
  }, [warehouses]);

  const handleEdit = useCallback(() => {
    snapshotRef.current = cloneItems(items);
    setFormMode(FormMode.Edit);
  }, [items]);

  const handleCreate = useCallback(() => {
    snapshotRef.current = cloneItems(items);
    setFormMode(FormMode.Create);
  }, [items]);

  const handleCancel = useCallback(() => {
    setItems(cloneItems(snapshotRef.current));
    setFormMode(FormMode.View);
  }, []);

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      const normalizedItems = items
        .filter(it => it.materialCode && it.warehouseId)
        .map(it => ({ ...it, amount: it.quantity * it.unitPrice }));
      await ktService.saveOpeningInventory({ year: Number(year), items: normalizedItems });
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      setFormMode(FormMode.View);
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.saveError), type: 'error' });
    } finally {
      setSaving(false);
    }
  }, [year, items, dispatch, load]);

  const materialOptions = useMemo(
    () => materials.map(m => ({ value: m.code, label: `${m.code} — ${m.name}` })),
    [materials],
  );
  const warehouseOptions = useMemo(
    () => warehouses.map(w => ({ value: w.id, label: `${w.code} — ${w.name}` })),
    [warehouses],
  );
  const warehouseFilterOptions = useMemo(
    () => [{ value: '', label: labels.warehouseFilterAll }, ...warehouseOptions],
    [warehouseOptions],
  );

  const displayedRows = useMemo(() => {
    if (isEditing) return items;
    return warehouseFilter ? items.filter(it => it.warehouseId === warehouseFilter) : items;
  }, [items, warehouseFilter, isEditing]);

  const { showTableLoading } = useCatalogTableBusy(loading);

  const headerHint = useMemo(() => {
    if (formMode === FormMode.Create) return labels.createHint;
    if (formMode === FormMode.Edit) return labels.editHint;
    return labels.viewHint;
  }, [formMode]);

  const toolbarActions = useMemo((): LinListToolbarActionDef[] => {
    const left: LinListToolbarActionDef[] = [
      {
        id: 'refresh',
        placement: 'left',
        action: 'refresh',
        visible: true,
        disabled: isEditing,
        onClick: load,
        testId: `${TEST_ID}-toolbar-refresh-btn`,
      },
    ];

    if (isView) {
      const right: LinListToolbarActionDef[] = canWrite
        ? (hasRows
          ? [{
            id: 'edit',
            placement: 'right',
            action: 'edit',
            visible: true,
            onClick: handleEdit,
            testId: `${TEST_ID}-toolbar-edit-btn`,
          }]
          : [{
            id: 'create',
            placement: 'right',
            action: 'create',
            variant: 'primary',
            visible: true,
            onClick: handleCreate,
            testId: `${TEST_ID}-toolbar-add-btn`,
          }])
        : [];
      return [...left, ...right];
    }

    return [
      ...left,
      {
        id: 'add-row',
        placement: 'right',
        label: labels.addRow,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: addRow,
        testId: `${TEST_ID}-toolbar-add-row-btn`,
      },
      {
        id: 'cancel',
        placement: 'right',
        label: labels.cancel,
        variant: 'secondary',
        visible: true,
        disabled: saving,
        onClick: handleCancel,
        testId: `${TEST_ID}-toolbar-cancel-btn`,
      },
      {
        id: 'save',
        placement: 'right',
        visible: true,
        testId: `${TEST_ID}-toolbar-save-btn`,
        render: () => (
          <Button
            variant="primary"
            size="sm"
            loading={saving}
            disabled={saving}
            data-testid={`${TEST_ID}-save`}
            onClick={handleSave}
          >
            {labels.save}
          </Button>
        ),
      },
    ];
  }, [
    isView,
    isEditing,
    hasRows,
    canWrite,
    load,
    handleEdit,
    handleCreate,
    handleCancel,
    handleSave,
    addRow,
    saving,
  ]);

  const listFilters = useMemo(
    () => (
      <ErpListHeaderFilters
        testIdPrefix={TEST_ID}
        filterCols={2}
        filterMaxWidthPx={1000}
      >
        <div className={erp.field} data-testid={`${TEST_ID}-field-year`}>
          <Select
            label={labels.filterYear}
            value={year}
            onChange={e => setYear(e.target.value)}
            options={yearOptions()}
            disabled={isEditing}
            data-testid={`${TEST_ID}-year`}
          />
        </div>
        <div className={erp.field} data-testid={`${TEST_ID}-field-warehouse-filter`}>
          <Select
            label={labels.filterWarehouse}
            value={warehouseFilter}
            onChange={e => setWarehouseFilter(e.target.value)}
            options={warehouseFilterOptions}
            disabled={isEditing}
            data-testid={`${TEST_ID}-warehouse-filter`}
          />
        </div>
      </ErpListHeaderFilters>
    ),
    [year, warehouseFilter, warehouseFilterOptions, isEditing],
  );

  const listBody = !showTableLoading && displayedRows.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty(year)}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table`}>
      <table className={erp.table}>
        <thead>
          <tr>
            <th>{labels.colMaterialCode}</th>
            <th>{labels.colMaterialName}</th>
            <th>{labels.colWarehouse}</th>
            <th className={erp.colRight}>{labels.colQty}</th>
            <th className={erp.colRight}>{labels.colUnitPrice}</th>
            <th className={erp.colRight}>{labels.colAmount}</th>
            {isEditing ? <th>{labels.colActions}</th> : null}
          </tr>
        </thead>
        <tbody>
          {displayedRows.map((it, displayIdx) => {
            const sourceIndex = items.indexOf(it);
            const rowIdx = sourceIndex >= 0 ? sourceIndex : displayIdx;
            const rowTestId = `${TEST_ID}-row-${displayIdx + 1}`;
            return (
              <tr key={`${it.materialCode || 'new'}-${it.warehouseId || rowIdx}-${rowIdx}`} data-testid={rowTestId}>
                <td>
                  {isView ? (
                    <code data-testid={`${rowTestId}-material`}>{it.materialCode || '—'}</code>
                  ) : (
                    <Select
                      value={it.materialCode}
                      onChange={e => {
                        const material = materials.find(m => m.code === e.target.value);
                        updateItem(rowIdx, {
                          materialCode: e.target.value,
                          materialName: material?.name ?? '',
                          unitCode: material?.unitCode ?? '',
                        });
                      }}
                      options={materialOptions}
                      placeholder={labels.colMaterialSelectPlaceholder}
                      data-testid={`${rowTestId}-material`}
                    />
                  )}
                </td>
                <td>{it.materialName ?? '—'}</td>
                <td>
                  {isView ? (
                    <span data-testid={`${rowTestId}-warehouse`}>{it.warehouseName ?? '—'}</span>
                  ) : (
                    <Select
                      value={it.warehouseId}
                      onChange={e => {
                        const warehouse = warehouses.find(w => w.id === e.target.value);
                        updateItem(rowIdx, {
                          warehouseId: e.target.value,
                          warehouseName: warehouse?.name ?? '',
                        });
                      }}
                      options={warehouseOptions}
                      placeholder={labels.colWarehouseSelectPlaceholder}
                      data-testid={`${rowTestId}-warehouse`}
                    />
                  )}
                </td>
                <td className={erp.colRight}>
                  {isView ? (
                    <span data-testid={`${rowTestId}-qty`}>{it.quantity}</span>
                  ) : (
                    <NumberInput
                      value={it.quantity}
                      onChange={val => updateItem(rowIdx, { quantity: Number(val) || 0 })}
                      data-testid={`${rowTestId}-qty`}
                    />
                  )}
                </td>
                <td className={erp.colRight}>
                  {isView ? (
                    <span data-testid={`${rowTestId}-price`}>{formatVnd(it.unitPrice)}</span>
                  ) : (
                    <MoneyInput
                      value={it.unitPrice}
                      onChange={val => updateItem(rowIdx, { unitPrice: Number(val) || 0 })}
                      data-testid={`${rowTestId}-price`}
                    />
                  )}
                </td>
                <td className={erp.colRight}>
                  <span data-testid={`${rowTestId}-amount`}>{formatVnd(it.amount)}</span>
                </td>
                {isEditing ? (
                  <td>
                    <Button
                      variant="danger"
                      size="sm"
                      onClick={() => deleteRow(rowIdx)}
                      data-testid={`${rowTestId}-delete`}
                    >
                      {labels.deleteRow}
                    </Button>
                  </td>
                ) : null}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.catalogListRoot}
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
      data-form-mode={formMode}
    >
      <LinPageLayout
        kind="catalog"
        filterBarLayout="compact"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={erp.catalogListPage}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-boxes',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        toolbarProps={{
          testIdPrefix: TEST_ID,
          profile: 'catalog',
          actions: toolbarActions,
        }}
        listTitle={labels.listTitle}
        filters={listFilters}
        filterMaxWidthPx={1000}
        filtersTestId={`${TEST_ID}-filters`}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoDuVatTuPage;
